import heapq

class Solution(object):
    def resultsArray(self, queries, k):
        # Max-heap of size k (negate for Python's min-heap)
        heap = []  # max-heap: store negatives
        result = []
        for x, y in queries:
            d = abs(x) + abs(y)
            if len(heap) < k:
                heapq.heappush(heap, -d)
            elif d < -heap[0]:
                heapq.heapreplace(heap, -d)
            result.append(-heap[0] if len(heap) == k else -1)
        return result
